import numpy as np

def solve(grid):
    inp = np.array(grid)
    H, W = inp.shape

    # Find separator rows and cols (>50% value 5)
    sep_rows = [r for r in range(H) if np.sum(inp[r] == 5) > W // 2]
    sep_cols = [c for c in range(W) if np.sum(inp[:, c] == 5) > H // 2]

    # Determine row/col ranges
    def get_ranges(seps, total):
        ranges = []
        prev = 0
        for s in seps:
            if s > prev:
                ranges.append((prev, s))
            prev = s + 1
        if prev < total:
            ranges.append((prev, total))
        return ranges

    row_ranges = get_ranges(sep_rows, H)
    col_ranges = get_ranges(sep_cols, W)

    N = row_ranges[0][1] - row_ranges[0][0]  # template size

    # Extract templates from row 0
    templates = {}
    template_colors = []
    for ci, (c0, c1) in enumerate(col_ranges):
        r0, r1 = row_ranges[0]
        cell = inp[r0:r1, c0:c1]
        colors = set(cell.flatten()) - {0}
        color = list(colors)[0]
        template_colors.append(color)
        pattern = (cell > 0).astype(int)
        templates[int(color)] = pattern

    # Extract markers from row 2
    markers = {}
    for ci, (c0, c1) in enumerate(col_ranges):
        r0, r1 = row_ranges[2]
        cell = inp[r0:r1, c0:c1]
        colors = set(cell.flatten()) - {0}
        if colors:
            marker = list(colors)[0]
            markers[int(template_colors[ci])] = int(marker)

    # Extract placement from row 1
    placement = {}
    for ci, (c0, c1) in enumerate(col_ranges):
        r0, r1 = row_ranges[1]
        cell = inp[r0:r1, c0:c1]
        for r in range(cell.shape[0]):
            for c in range(cell.shape[1]):
                if cell[r, c] != 0:
                    placement[(r, c)] = int(cell[r, c])

    # Build output
    out_size = N * N
    output = np.zeros((out_size, out_size), dtype=int)

    for (br, bc), color in placement.items():
        pattern = templates[color]
        new_color = markers[color]
        output[br*N:(br+1)*N, bc*N:(bc+1)*N] = pattern * new_color

    return output.tolist()

